INSERT INTO public.contents (id, title, description, "imageUrl", body, "isProcessed", "createdAt", "updatedAt", "systemPrompt") VALUES ('cmmlopwia000001nx73nfytkl', 'МОНГОЛ УЛСЫН ҮНДСЭН ХУУЛЬ', '', 'data:image/png;base64,', 'МОНГОЛ УЛСЫН ҮНДСЭН ХУУЛЬ
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('a05541a0-3194-48d6-80ba-d8dfba077297', 'cmmlopwia000001nx73nfytkl', 'лон зарлаж, жар хоногийн дотор явуулна. Шинэ сонгогдсон гишүүд тангараг өргөтөл Улсын Их Хурал бүрэн эрхээ хадгална.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('d8327d50-68a1-43f7-832f-03c877e3def2', 'cmmlopwia000001nx73nfytkl', ' оны 12 дугаар сарын 14-ний өдөр баталсан Монгол Улсын Үндсэн хуульд оруулсан нэмэлт, өөрчлөлтөөр нэмсэн. Мөн хэсгийг 2019 оны 11 дүгээр сарын 14-ний өдөр баталсан Монгол Улсын Үндсэн хуульд оруулсан нэмэлт, өөрчлөлтөөр өөрчлөн найруулсан./ 3.Ерөнхийлөгч Үндсэн хуулийн гучин есдүгээр зүйлийн 2 дахь хэсэгт заасны дагуу Ерөнхий сайдыг томилох саналыг Улсын Их Хуралд анх оруулснаас хойш дөчин тав хоногийн дотор, эсхүл Үндсэн хуулийн дөчин гуравдугаар зүйлийн 1 дэх хэсэгт заасны дагуу Ерөнхий сайдыг огцруулснаас, түүнчлэн дөчин дөрөвдүгээр зүйлийн 2 дахь хэсэгт заасны дагуу Ерөнхий сайдыг огцорсонд тооцсоноос хойш гуч хоногийн дотор Улсын Их Хурал Ерөнхий сайдыг томилоогүй бол Ерөнхийлөгч Улсын Их Хурлыг тараах шийдвэр гаргана.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('212530d9-974c-4fe0-89f0-5d312f1ee58d', 'cmmlopwia000001nx73nfytkl', 'МОНГОЛ УЛСЫН ҮНДСЭН ХУУЛЬ
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('9b1febc9-0670-4dbe-8b87-952947da1a27', 'cmmlopwia000001nx73nfytkl', 'д түмний мэдэлд байна. Монголын ард түмэн төрийн үйл хэрэгт шууд оролцож, мөн сонгож байгуулсан төрийн эрх барих төлөөлөгчдийн байгууллагаараа уламжлан энэхүү эрхээ эдэлнэ.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('daa559e8-46f7-46d0-83a0-9382c6cee6a0', 'cmmlopwia000001nx73nfytkl', 'згаарлаж болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('37db6ad6-782d-4ab5-8658-7001db386643', 'cmmlopwia000001nx73nfytkl', 'аарахгүй. Иргэд хувийн өмчийнхөө газрыг худалдах, арилжих, бэлэглэх, барьцаалах зэргээр гадаадын иргэн, харьяалалгүй хүний өмчлөлд шилжүүлэх, түүнчлэн төрийн эрх бүхий байгууллагын зөвшөөрөлгүйгээр бусдад эзэмшүүлэх, ашиглуулахыг хориглоно. 4.Төр газрын эзэнд газартай нь холбогдсон үүрэг хүлээлгэх, улсын тусгай хэрэгцээг үндэслэн нөхөх олговортойгоор газрыг солих буюу эргүүлэн авах, уг газрыг хүн амын эрүүл мэнд, байгаль хамгаалал, үндэсний аюулгүй байдлын ашиг сонирхолд харшаар ашиглавал хураан авч болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('fcd06550-7b38-4b85-aae4-f67c707ecdfc', 'cmmlopwia000001nx73nfytkl', 'йгаль хамгаалал, үндэсний аюулгүй байдлын ашиг сонирхолд харшаар ашиглавал хураан авч болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('a70d1119-a055-45bc-95ef-6fca7aa9146b', 'cmmlopwia000001nx73nfytkl', 'ар тогтнолыг батлан хамгаалж, үндэсний аюулгүй байдал, нийгмийн дэг журмыг хангах нь төрийн үүрэг мөн.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('3c1e1242-6c57-4fb5-9684-6c53d013e1a4', 'cmmlopwia000001nx73nfytkl', 'Далбааны өргөн, урт нь 1:2-ын харьцаатай байна.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('9516ea89-d4b6-4161-8190-a66409d5c89b', 'cmmlopwia000001nx73nfytkl', '7.Төрийн бэлгэ тэмдгийг дээдлэн хэрэглэх журам, төрийн дууллын үг, аяыг хуулиар бататгана. ### Арван гуравдугаар зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('db06ef98-820e-456c-b540-8770d080b1d4', 'cmmlopwia000001nx73nfytkl', '### Арван тавдугаар зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('a5676e3f-20aa-4d81-b103-d640a33c4c2a', 'cmmlopwia000001nx73nfytkl', 'гоно. Иргэд төрөөс тавих шаардлагад нийцсэн хувийн сургууль байгуулан ажиллуулж болно;
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('97ae834d-ee8b-4c40-b474-7c87419a8d49', 'cmmlopwia000001nx73nfytkl', 'бүл, эх нялхас, хүүхдийн ашиг сонирхлыг төр хамгаална;
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('b8d6b97c-88b7-4558-b055-1436d6c9bb5a', 'cmmlopwia000001nx73nfytkl', 'аан хэрэглэхийг хориглоно;
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('31c84273-4eff-4edb-8ca5-0c13a93b2485', 'cmmlopwia000001nx73nfytkl', 'байнга оршин суух газраа сонгох, гадаадад явах, оршин суух, эх орондоо буцаж ирэх эрхтэй. Гадаадад явах, оршин суух эрхийг үндэсний болон хүн амын аюулгүй байдлыг хангах, нийгмийн хэв журмыг хамгаалахын тулд зөвхөн хуулиар хязгаарлаж болно. ### Арван долдугаар зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('3b631350-e29f-4f32-9839-620c507e7923', 'cmmlopwia000001nx73nfytkl', 'лалгүй хүнд эдлүүлэхдээ Монгол Улсын нэгдэн орсон олон улсын гэрээнд заасан хүний салшгүй эрхээс бусад эрхийн хувьд үндэсний болон хүн амын аюулгүй байдлыг хангах, нийгмийн хэв журмыг хамгаалахын тулд хуулиар зохих хязгаарлал тогтоож болно. ### Арван есдүгээр зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('20ec3d6e-afd5-4d9a-ab2f-56570173f953', 'cmmlopwia000001nx73nfytkl', 'лт нь нийтэд ил тод байна. Намын зохион байгуулалт, үйл ажиллагааны журам, санхүүжилт, төрөөс санхүүгийн дэмжлэг үзүүлэх нөхцөлийг хуулиар тогтооно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('6de6894b-3c52-48e5-a65b-077bb65210a8', 'cmmlopwia000001nx73nfytkl', ' жилийн дотор Улсын Их Хурлын сонгуулийн тухай хууль батлах, түүнд нэмэлт, өөрчлөлт оруулахыг хориглоно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('80335288-3a1d-4ec3-bed5-fcf9f8814833', 'cmmlopwia000001nx73nfytkl', 'өдөр баталсан Монгол Улсын Үндсэн хуульд оруулсан нэмэлт, өөрчлөлтөөр өөрчлөн найруулсан/
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('fa1ba563-c6ee-4649-aa17-7b2637cf0f21', 'cmmlopwia000001nx73nfytkl', 'анг батлах;
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('96b56e2e-be52-495b-96be-c288dee8b291', 'cmmlopwia000001nx73nfytkl', ' ард нийтийн санал асуулгыг хүчинтэйд тооцож, олонхийн санал авсан асуудлыг шийдвэрлэгдсэн гэж үзнэ;
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('c3ed2f25-fb15-413c-8f00-868b53042cb7', 'cmmlopwia000001nx73nfytkl', 'рах бодит аюул бий болсон, бусад улсаас цэргийн хүчээр түрэмгийлэн халдсан, эсхүл тийнхүү халдах нь бодитой болсон үед дайны байдал зарлаж болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('fd1b776d-5e11-4a56-8434-eba168df8d5a', 'cmmlopwia000001nx73nfytkl', 'сад байгууллага хуулийн төслийн тухай саналаа хууль санаачлагчид уламжилна.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('afa38b2f-a6bc-4b32-bd7b-c79446a2538b', 'cmmlopwia000001nx73nfytkl', 'цэн ирснээр хүчинтэйд үзэж, Үндсэн хуульд өөрөөр заагаагүй бол хуралдаанд оролцсон гишүүдийн олонхийн саналаар асуудлыг шийдвэрлэнэ.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('68cb979f-7388-4943-84e3-3986b00c6f58', 'cmmlopwia000001nx73nfytkl', 'ндсэн хууль, бусад хуульд заасан, эсхүл хуралдаанд оролцсон гишүүдийн олонхи дэмжсэн бол нууц санал хураалт явуулна.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('afc5f016-ff25-4466-b67a-becc4ce3169b', 'cmmlopwia000001nx73nfytkl', 'улна.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('f0b09498-f748-4b5d-b099-75d1e0a05a2a', 'cmmlopwia000001nx73nfytkl', 'ж шүүх тогтоовол Улсын Их Хурал түүнийг гишүүнээс нь эгүүлэн татна.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('6d3735c1-10d0-4254-9efe-e0034837c050', 'cmmlopwia000001nx73nfytkl', 'оо байнга оршин суусан, Монгол Улсын уугуул иргэнийг зургаан жилийн хугацаагаар зөвхөн нэг удаа сонгоно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('8c8ae880-dc2f-4a2b-8bcd-4e3a0a50ac01', 'cmmlopwia000001nx73nfytkl', ', Улсын Их Хурал, Засгийн газрын гишүүн, хуулиар тогтоосон үүрэгт нь үл хамаарах бусад ажил, албан тушаал хавсарч болохгүй. Хэрэв Ерөнхийлөгч өөр ажил, албан тушаал эрхэлж байгаа бол тангараг өргөсөн өдрөөсөө эхлэн уул үүргээс чөлөөлөгдөнө. ### Гучин хоёрдугаар зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('d88f410e-c38b-47fc-8449-2d191741ac6d', 'cmmlopwia000001nx73nfytkl', 'лсын тусгаар тогтнол, бүрэн эрхт байдал, ард түмнийхээ эрх чөлөө, үндэсний эв нэгдлийг эрхэмлэн хамгаалж, Үндсэн хуулийг дээдлэн сахиж, Ерөнхийлөгчийн үүргийг шударгаар биелүүлэхээ батлан тангараглая" хэмээн Улсын Их Хуралд тангараг өргөнө. ### Гучин гуравдугаар зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('320a0792-6cde-4c7d-96e8-03722ec4c3af', 'cmmlopwia000001nx73nfytkl', 'вшилцөн томилох буюу эгүүлэн татах;
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('9273e1b0-aea3-4821-a2cf-98728c23e533', 'cmmlopwia000001nx73nfytkl', 'оруулж болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('ae64af15-e5eb-4c35-bcee-b3a15dc32267', 'cmmlopwia000001nx73nfytkl', 'н Их Хурлын дарга хэрэгжүүлнэ. Энэ тохиолдолд Улсын Их Хурал Ерөнхийлөгчийн сонгуулийг дөрвөн сарын дотор зарлан явуулна.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('6570c5b5-b68a-45d2-9138-77a40e1b7a49', 'cmmlopwia000001nx73nfytkl', 'лцөж дараа соёрхон батлуулахаар Монгол Улсын олон улсын гэрээ байгуулах, хэрэгжүүлэх, түүнчлэн Засгийн газар хоорондын гэрээ байгуулах, цуцлах.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('06b82d3e-4f0f-4f02-afae-7ff32d987592', 'cmmlopwia000001nx73nfytkl', 'ишүүн Улсын Их Хуралд тангараг өргөнө.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('cb47f7a2-4705-4537-8c36-22568aad74d7', 'cmmlopwia000001nx73nfytkl', 'ий олонхийн саналаар шийдвэрлэнэ.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('f1466e74-5f96-4db2-a607-af152fb1cf57', 'cmmlopwia000001nx73nfytkl', ' зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('9d79bc8e-abf9-47fa-80f6-b8e489329b9f', 'cmmlopwia000001nx73nfytkl', 'сэн хуульд оруулсан нэмэлт, өөрчлөлтөөр өөрчлөн найруулсан./
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('e1f2b0ff-9911-4b98-97fc-631c77d5d9cd', 'cmmlopwia000001nx73nfytkl', ' түдгэлзүүлэх, огцруулах болон сахилгын бусад шийтгэл ногдуулах чиг үүрэг бүхий Шүүхийн сахилгын хороо ажиллах бөгөөд түүний бүрэн эрх, зохион байгуулалт, үйл ажиллагааны журам, бүрэлдэхүүнд тавих шаардлага, томилох журмыг хуулиар тогтооно. /Энэ хэсгийг 2019 оны 11 дүгээр сарын 14-ний өдөр баталсан Монгол Улсын Үндсэн хуульд оруулсан нэмэлт, өөрчлөлтөөр нэмсэн./', 38, 122, '{}', '[9.6228825e-05,0.019099053,-0.017184475,-0.041843697,0.00462978,0.029412348,0.033663478,0.023760857,0.013596172,-0.006270632,-0.017878357,-0.024536977,-0.0069777337,-0.001284969,0.08425702,0.013116799,-0.014213409,0.031864055,0.0025392938,-0.024694066,0.0039430573,-0.029715253,-0.008351056,0.0026759794,-0.020619284,-0.014429976,0.0143187875,0.011160992,0.038480263,-0.024652267,-0.0064222706,0.020461375,0.016323257,0.0034916687,0.0028913694,0.009624226,0.020720003,-0.017370848,0.00018171848,0.013799163,0.014072249,0.015516766,-0.0005649026,0.018145014,0.036898732,0.0050541274,-0.008696934,-0.024129055,-0.02254192,0.023266865,0.0138681475,0.0053375685,-0.026751822,-0.15494859,-0.025792846,-0.01032929,-0.025940362,-0.0038216547,0.008000851,0.015453268,-0.057551913,0.015782721,-0.01651566,0.0018620142,0.0086576985,0.01509955,0.008546469,0.022763813,-0.03216428,0.0008368001,-0.01208123,-0.005351312,-0.0029746285,-0.009983309,-0.019480746,-0.00878485,-0.022111516,-0.010712174,-0.027195143,0.020974243,0.0061606253,-0.018298935,0.012482149,0.0040791384,-0.0058951676,0.020263895,0.012950143,-0.006990655,0.0034532358,0.006562163,-0.016602911,-0.005850827,-0.036184646,-0.0004532437,-0.009231768,0.018463042,0.0056377016,-0.012672054,-0.0101007335,-0.0050044605,0.008205813,-0.0071725016,0.0026262517,-0.0097521255,0.005317036,-0.014159368,0.008755175,-0.0109174615,-0.006286574,-0.020412825,0.00081017474,-0.012