INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('107664fe-a24e-4d22-a4b5-7754778d970a', 'cmmlopwia000001nx73nfytkl', '/Энэ хэсгийг 2019 оны 11 дүгээр сарын 14-ний өдөр баталсан Монгол Улсын Үндсэн хуульд оруулсан нэмэлт, өөрчлөлтөөр нэмсэн./ ### Тавьдугаар зүйл.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('55c3aee9-e533-41d8-96fc-40ca8859544c', 'cmmlopwia000001nx73nfytkl', ' хуульд харшилбал түүнийг Улсын дээд шүүх өөрөө хүчингүй болгоно. Улсын дээд шүүхийн тайлбар хуульд харшилбал хуулийг дагаж биелүүлнэ.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('e5810136-75ff-4e5c-8844-ab849742eefe', 'cmmlopwia000001nx73nfytkl', 'эл мэдэхгүй хүнд хэргийн баримт сэлтийг хэлмэрчлүүлэн бүрэн танилцуулах бөгөөд шүүх хуралдаан дээр эх хэлээр нь үг хэлэх эрх олгоно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('8c94898b-0bfd-47b1-b2aa-5c5c20ce9878', 'cmmlopwia000001nx73nfytkl', 'н хугацаагаар томилно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('ae296c42-6646-4875-916a-d1f5fd5050be', 'cmmlopwia000001nx73nfytkl', 'үүрэг бол хуулиар тусгайлан олгосон чиг үүрэг, өөрийн удирдлага бүхий засаг захиргаа, нутаг дэвсгэр, эдийн засаг, нийгмийн цогцолбор мөн.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('73ac2b4e-15c1-43ca-ba74-051f638370ce', 'cmmlopwia000001nx73nfytkl', 'ол Улсын Үндсэн хуульд оруулсан нэмэлт, өөрчлөлтөөр өөрчлөн найруулсан./
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('a5805e82-19c9-4471-9b6e-249d67e9c57a', 'cmmlopwia000001nx73nfytkl', 'л, Ерөнхий сайд буюу харьяалах дээд шатны Засаг даргад гаргаж болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('f71e35da-0584-40fb-bbad-589ada7a830d', 'cmmlopwia000001nx73nfytkl', 'тусын нутаг дэвсгэрт хүчин төгөлдөр дагаж мөрдөнө.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('a438951b-64da-4cba-8a93-ee2d5ec9b378', 'cmmlopwia000001nx73nfytkl', 'йн шийдвэр, анх илгээсэн байгууллагын саналыг үндэслэн Улсын Их Хурал эгүүлэн татаж болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('c6a7bee2-b949-414f-ac29-e7e610e53ceb', 'cmmlopwia000001nx73nfytkl', ' Монгол Улсын олон улсын гэрээ нь Үндсэн хуульд нийцээгүй гэж Үндсэн хуулийн цэц шийдвэр гаргавал зохих хууль, зарлиг, батламж, шийдвэр хүчингүй болно.
INSERT INTO public.chunks (id, "contentId", content, "chunkIndex", "tokenCount", metadata, embedding, "createdAt", tsv) VALUES ('0847ccce-0f14-4350-9306-84497b3f6dff', 'cmmlopwia000001nx73nfytkl', 'үн ажлаа эхэлтэл дахин авч хэлэлцэхгүй.
